var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......유미나?","JPN":"……ヤナギ・ミナ？","ENG":"Yoo Mina?","TWN":"……劉米娜。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"비, 비숍?!","JPN":"ビ、ビショップ！？","ENG":"B-Bishop!","TWN":"大、大主教？！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어째서 여기에......?","JPN":"どうしてここに……？","ENG":"Why are you here?","TWN":"妳怎麼會在這裡……？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 아직도 리플레이서에게 협력하고 있는 거야?","JPN":"まさか、今でもリプレイサーに協力してるの？","ENG":"Are you still cooperating with the Replacers?","TWN":"難道妳現在還在幫助克隆集團嗎？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"너무 그렇게 윽박지르지 말게.","JPN":"そう迫るな。","ENG":"Don't yell at her too much.","TWN":"別嚇她了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그녀는 아직 어려. 주변의 압력을 이겨내고 자기 생각을 솔직하게 말하기엔 조금 이르지.","JPN":"彼女はまだ若い。\\n周りの目を気にせず、自分の考えを正直に話すのはまだ早いだろう。","ENG":"She's still young. She's not mature enough to express her honest opinions without being affected by outside pressures.","TWN":"她還年輕，要她克服周圍的壓力，坦率說出自己的想法還太早了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다, 당신은?! 그때 그 홀로그램에서 본......!!","JPN":"あ、あなたは！？　あの時のホログラムに出てた……！！","ENG":"Y-you! I saw you in the hologram!","TWN":"你、你是？！那個時候在全息影像看到的……！！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"당신이...... 바로 리플레이서 킹이군요.","JPN":"あなたが……リプレイサー・キングなんですね。","ENG":"You're the Replacer King.","TWN":"你就是……克隆．帝皇啊。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"실비아 양이 속한 델타세븐의 전 부사령관이었다는......","JPN":"シルビアさんがいるデルタセブンの元副司令官だったという……","ENG":"The former deputy commander of Delta Seven, where Sylvia now works.","TWN":"希爾維亞小姐所屬的第七三角洲部隊前副司令官……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"안타깝지만...... 이제는 지나간 옛 이야기지.","JPN":"残念ながら……もう昔の話だ。","ENG":"Ah, they're fond memories, but that was ages ago.","TWN":"很遺憾……那都是過去的事情了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그보다, 뉴 오하이오에 승선한 것을 환영하네.","JPN":"それより、ニューオハイオへの乗船を歓迎しよう。","ENG":"Anyway, welcome aboard the New Ohio.","TWN":"歡迎你們登上新俄亥俄。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"직접 만나는 건 처음이지만, 자네들의 이름은 그동안 나도 많이 들었지.","JPN":"初対面だが、君たちの名は聞きなれている。","ENG":"It's my first time meeting you, but I've heard your names many times over.","TWN":"雖然我們是第一次見面，但你們的名字我很常聽到。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"우리 간부들이 자네들 덕분에 꽤나 고생했다고 하더군.","JPN":"うちの幹部たちが、君たちのおかげでずいぶん苦労したと言っていたな。","ENG":"My officers say you gave them a hard time.","TWN":"聽說我們的幹部因為你們，吃了很多苦頭呢。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"대단해. 이건 가감 없는 내 진심일세.","JPN":"すごいな。これは私の素直な感想だ。","ENG":"That's impressive. I mean it, I'm truly impressed.","TWN":"真厲害，這是我發自內心的話語。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"일을 벌인 내가 할 말은 아니지만, 어린 나이에 험한 사건들을 겪으면서 꽤나 시련이 많았을 것 같은데......","JPN":"この事態を作った私の言うことではないが、\\n若くして散々な目に遭って大変だったと思うが……","ENG":"I'm the one who started all this, so it might be awkward coming from me, but you've experienced so many hardships at such a young age...","TWN":"雖然是我惹的事端，這話不該由我來說，但是妳小小年紀就經歷這麼險惡的事情，恐怕通過很多的試煉吧……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"결국 그 모든 것들을 극복하고 누구보다 먼저 내 앞에 도달했군.","JPN":"ついにその全てを乗り越え、誰よりも早く私のもとへたどり着いた。","ENG":"And you overcame everything to come stand in front of me before anyone else did.","TWN":"但是妳最終還是克服了這一切，比誰都還要先來到我的面前。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"자네들은 내 환영을 받을 만한 가치가 있어. 다시 한 번 환영하네.","JPN":"君たちには私の歓迎を受ける資格がある。改めて、歓迎する。","ENG":"You both deserve my warm welcome. Again, welcome aboard.","TWN":"妳值得接受我的歡迎。我要在這裡再次歡迎妳。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};